   139	static void ngap_dump_served_guami(const ngap_gNB_amf_data_t *amf_desc_p)
   140	{
   141	  const struct served_guami_s *guami_p;
   142	  const struct plmn_identity_s *plmn_p;
   143	  const struct served_region_id_s *region_p;
   144	  const struct amf_set_id_s *set_id_p;
   145	  const struct amf_pointer_s *pointer_p;
   146	
   147	  NGAP_DEBUG("Served GUAMIs for AMF %s (assoc_id=%d):\n",
   148	             amf_desc_p->amf_name ? amf_desc_p->amf_name : "(no name)",
   149	             amf_desc_p->assoc_id);
   150	
   151	  STAILQ_FOREACH(guami_p, &amf_desc_p->served_guami, next)
   152	  {
   153	    NGAP_DEBUG(" GUAMI:\n");
   154	    STAILQ_FOREACH(plmn_p, &guami_p->served_plmns, next) {
   155	      NGAP_DEBUG("   PLMN: MCC=%03d, MNC=%0*d\n", plmn_p->mcc, plmn_p->mnc_digit_length, plmn_p->mnc);
   156	    }
   157	    STAILQ_FOREACH(region_p, &guami_p->served_region_ids, next) {
   158	      NGAP_DEBUG("   AMF Region ID: %d\n", region_p->amf_region_id);
   159	    }
   160	    STAILQ_FOREACH(set_id_p, &guami_p->amf_set_ids, next) {
   161	      NGAP_DEBUG("   AMF Set ID: %d\n", set_id_p->amf_set_id);
   162	    }
   163	    STAILQ_FOREACH(pointer_p, &guami_p->amf_pointers, next) {
   164	      NGAP_DEBUG("   AMF Pointer: %d\n", pointer_p->amf_pointer);
   165	    }
   166	  }
   167	}
